import Foundation

func solve(words: Array<String>) -> Array<Int64> {
    let n = words.count
    var answer = Array<Int64>(repeating: 0, count: n)

    for i in 0..<n {
        var newWords = words
        newWords.remove(at: i)

        var maxPrefix = 0
        for j in 0..<newWords.count - 1 {
            let prefixLength = commonPrefixLength(newWords[j], newWords[j + 1])
            if prefixLength > maxPrefix {
                maxPrefix = prefixLength
            }
        }
        answer[i] = Int64(maxPrefix)
    }

    return answer
}

func commonPrefixLength(_ s: String, _ t: String) -> Int {
    let sArray = Array(s)
    let tArray = Array(t)
    var minLength = min(sArray.count, tArray.count)

    var i = 0
    while i < minLength && sArray[i] == tArray[i] {
        i += 1
    }

    return i
}
